import './Transactions.css';
import Navbar from "../../components/Navbar/Navbar";
import TransactionRow from '../../components/TransactionRow/TransactionRow';
import { useState } from 'react';

function Transactions({transactions, setTransactions}) {
    const [selectedCategory, setSelectedCategory] = useState("All");
    return (
        <>
        <div className="search-sort-container">
            <div className="filter-container">
                <select
                    value={selectedCategory}
                    onChange={(e) => setSelectedCategory(e.target.value)}
                    className="filter-select"
                >
                    <option value="All">All Categories</option>
                    <option value="Food">Food</option>
                    <option value="Travel">Travel</option>
                    <option value="Shopping">Shopping</option>
                    <option value="Salary">Salary</option>
                </select>
            </div>
            <div className="search-container">
                <i className="fa-brands fa-sistrix search-icon"></i>
                <input className='search-button' type="search" placeholder='Search' />
            </div>
        </div>

        <p className='main-heading'>Transaction List</p>
        {transactions.map((transaction) => (
        <TransactionRow key={transaction.id} transaction={transaction} transactions={transactions} setTransactions={setTransactions}/>
        ))}
        </>
    );
};

export default Transactions;
